// A JSX expression is just a React.createElement call in disguise:
const icon = <SaveIcon size={16} />;  // React element (a plain object)
const alert = <p className="alert">{message}</p>;

// You can pass them anywhere a value is accepted:
console.log(typeof icon);  // 'object'
const elements = [icon, alert];  // array of React elements

// Passing as a prop:
<Button leadingIcon={<SaveIcon />} label="Save" />

function Button({ leadingIcon, trailingIcon, children, ...rest }) {
  return (
    <button {...rest}>
      {leadingIcon && (
        <span className="btn__icon btn__icon--leading" aria-hidden>
          {leadingIcon}
        </span>
      )}
      {children}
      {trailingIcon && (
        <span className="btn__icon btn__icon--trailing" aria-hidden>
          {trailingIcon}
        </span>
      )}
    </button>
  );
}

// Callers choose any icon without touching Button:
<Button leadingIcon={<SaveIcon />} onClick={save}>Save</Button>
<Button trailingIcon={<ExternalLinkIcon />} href="/docs">Docs</Button>
<Button leadingIcon={<Spinner size="sm" />} disabled>Saving…</Button>

function Dialog({ header, footer, children, onClose }) {
  return (
    <div role="dialog" aria-modal className="dialog">
      <div className="dialog__header">
        {header}
        <button onClick={onClose} aria-label="Close">✕</button>
      </div>
      <div className="dialog__body">{children}</div>
      {footer && <div className="dialog__footer">{footer}</div>}
    </div>
  );
}

// Each slot is independently authored by the caller:
<Dialog
  header={<h2>Delete item?</h2>}
  footer={
    <div className="btn-row">
      <Button onClick={onClose}>Cancel</Button>
      <Button variant="danger" onClick={handleDelete}>Delete</Button>
    </div>
  }
  onClose={closeDialog}
>
  <p>This will permanently remove the item from your account.</p>
</Dialog>

// A heading that renders any element type:
function Heading({ as: Tag = 'h2', children, className = '', ...rest }) {
  //               ^^
  //   Rename as → Tag (uppercase), so JSX recognises it as a component/element
  return (
    <Tag className={`heading ${className}`} {...rest}>
      {children}
    </Tag>
  );
}

// Renders a native <h1>:
<Heading as="h1">Page Title</Heading>

// Renders a native <h3>:
<Heading as="h3" className="section-title">Section</Heading>

// Renders a custom component:
<Heading as={AnimatedHeading}>Welcome</Heading>

// Renders a React Router link styled as a button:
<Button as={Link} to="/dashboard">Dashboard</Button>

function UserCard({ user, isCurrentUser }) {
  // Build the action element before the return
  const action = isCurrentUser
    ? <button onClick={editProfile}>Edit profile</button>
    : <button onClick={() => follow(user.id)}>Follow</button>;

  const badge = user.role === 'admin'
    ? <AdminBadge />
    : null;

  return (
    <div className="user-card">
      <Avatar src={user.photo} />
      <div>
        <h3>{user.name} {badge}</h3>
        <p>{user.bio}</p>
      </div>
      {action}    {/* pre-built element goes here */}
    </div>
  );
}

function SidebarLayout({ sidebar, children }) {
  return (
    <div className="layout">
      <aside className="layout__sidebar">
        {sidebar}   {/* rendered exactly as provided; SidebarLayout cannot touch sidebar's props */}
      </aside>
      <main className="layout__main">
        {children}
      </main>
    </div>
  );
}

// The caller controls what sidebar renders and what props it has:
<SidebarLayout
  sidebar={<NavigationMenu items={navItems} collapsed={isMobile} />}
>
  <ArticlePage />
</SidebarLayout>

// Element prop — eager: ExpensiveChart is created unconditionally
<Dashboard sidePanel={<ExpensiveChart data={data} />} />
// ExpensiveChart runs its rendering code even if sidePanel is hidden

// Render prop — lazy: ExpensiveChart is created only when needed
<Dashboard sidePanel={() => <ExpensiveChart data={data} />} />
// ExpensiveChart is not created until Dashboard calls sidePanel()

// Inside Dashboard:
function Dashboard({ sidePanel }) {
  const [panelOpen, setPanelOpen] = useState(false);
  return (
    <div>
      <button onClick={() => setPanelOpen(o => !o)}>Toggle panel</button>
      {panelOpen && (
        typeof sidePanel === 'function'
          ? sidePanel()       // call if render prop
          : sidePanel         // render if element
      )}
    </div>
  );
}

import { ReactNode, ReactElement, ElementType, ComponentPropsWithoutRef } from 'react';

// ReactNode: anything React can render (element, string, array, null, undefined)
type ButtonProps = {
  leadingIcon?: ReactNode;    // flexible: string, element, null all OK
  children: ReactNode;
};

// ReactElement: specifically a React element (not strings/numbers/null)
type BadgeProps = {
  icon: ReactElement;         // caller MUST pass an element, not a string
};

// ElementType: a component type (function, class, or native tag string)
type PolymorphicHeadingProps<T extends ElementType = 'h2'> = {
  as?: T;
  children: ReactNode;
} & Omit<ComponentPropsWithoutRef<T>, 'as'>;

function Heading<T extends ElementType = 'h2'>({
  as,
  children,
  ...rest
}: PolymorphicHeadingProps<T>) {
  const Tag = (as ?? 'h2') as ElementType;
  return <Tag {...rest}>{children}</Tag>;
}

// 1. Alert with an optional action button
function Alert({ severity = 'info', icon, message, action }) {
  return (
    <div role="alert" className={`alert alert--${severity}`}>
      {icon && <span className="alert__icon" aria-hidden>{icon}</span>}
      <p className="alert__message">{message}</p>
      {action && <div className="alert__action">{action}</div>}
    </div>
  );
}

<Alert
  severity="warning"
  icon={<WarningIcon />}
  message="Your session expires in 5 minutes."
  action={<button onClick={renew}>Renew session</button>}
/>

// 2. List with a customisable empty state
function DataList({ items, emptyState = <p>No items yet.</p> }) {
  if (items.length === 0) return emptyState;
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

<DataList
  items={users}
  emptyState={
    <div className="empty">
      <TeamIcon />
      <p>No team members yet.</p>
      <Button onClick={invite}>Invite someone</Button>
    </div>
  }
/>

// AppShell.jsx — the layout scaffold
function AppShell({
  topBar,
  sidebar,
  breadcrumbs = null,
  children,
  statusBar = null,
}) {
  return (
    <div className="shell">
      {/* Fixed top navigation */}
      <header className="shell__top">{topBar}</header>

      <div className="shell__body">
        {/* Optional collapsible sidebar */}
        {sidebar && (
          <nav className="shell__sidebar">{sidebar}</nav>
        )}

        <div className="shell__content">
          {/* Optional breadcrumb trail */}
          {breadcrumbs && (
            <div className="shell__breadcrumbs">{breadcrumbs}</div>
          )}

          {/* Primary content slot */}
          <main>{children}</main>
        </div>
      </div>

      {/* Optional status bar at the bottom */}
      {statusBar && (
        <footer className="shell__status">{statusBar}</footer>
      )}
    </div>
  );
}

// Usage in a specific page route:
function ProjectPage({ project }) {
  return (
    <AppShell
      topBar={
        <Navbar
          logo={<Logo />}
          user={currentUser}
          onLogout={logout}
        />
      }
      sidebar={<ProjectTree projectId={project.id} />}
      breadcrumbs={
        <Breadcrumbs
          items={[
            { label: 'Projects', href: '/projects' },
            { label: project.name, href: `/projects/${project.id}` },
          ]}
        />
      }
      statusBar={<SyncStatus lastSaved={project.updatedAt} />}
    >
      <ProjectEditor project={project} />
    </AppShell>
  );
}

function Toolbar({ leading = [], trailing = [], children }) {
  return (
    <div className="toolbar">
      <div className="toolbar__leading">
        {leading.map((item, i) => (
          <div key={i} className="toolbar__item">{item}</div>
        ))}
      </div>
      <div className="toolbar__center">{children}</div>
      <div className="toolbar__trailing">
        {trailing.map((item, i) => (
          <div key={i} className="toolbar__item">{item}</div>
        ))}
      </div>
    </div>
  );
}

// Usage:
<Toolbar
  leading={[
    <BackButton />,
    <ForwardButton />,
    <ReloadButton />,
  ]}
  trailing={[
    <ShareButton />,
    <BookmarkButton />,
    <MoreMenuButton />,
  ]}
>
  <AddressBar />
</Toolbar>

function Tabs({ tabs, panels, defaultIndex = 0 }) {
  const [active, setActive] = useState(defaultIndex);

  return (
    <div className="tabs">
      <div role="tablist">
        {tabs.map((tab, i) => (
          <button
            key={i}
            role="tab"
            aria-selected={active === i}
            onClick={() => setActive(i)}
          >
            {tab}
          </button>
        ))}
      </div>
      <div role="tabpanel">{panels[active]}</div>
    </div>
  );
}

// Usage — each tab label and panel is a React element:
<Tabs
  tabs={[
    <span>Overview</span>,
    <span>Files</span>,
    <><FileIcon /> Settings</>,
  ]}
  panels={[
    <OverviewPanel project={project} />,
    <FileTree projectId={project.id} />,
    <SettingsPanel projectId={project.id} />,
  ]}
/>

import { render, screen } from '@testing-library/react';
import Button from './Button';

test('renders leadingIcon when provided', () => {
  render(
    <Button leadingIcon={<span data-testid="save-icon" />} onClick={() => {}}>
      Save
    </Button>
  );
  expect(screen.getByTestId('save-icon')).toBeInTheDocument();
  expect(screen.getByRole('button', { name: /Save/ })).toBeInTheDocument();
});

test('renders without icon when omitted', () => {
  render(<Button onClick={() => {}}>Cancel</Button>);
  // No icon — query returns null, no error thrown
  expect(screen.queryByRole('img', { hidden: true })).not.toBeInTheDocument();
});

test('as prop renders correct element', () => {
  render(<Heading as="h1">Page Title</Heading>);
  // Testing Library queries by role; h1 has role heading with level 1
  expect(
    screen.getByRole('heading', { name: 'Page Title', level: 1 })
  ).toBeInTheDocument();
});
